import { createPublicClient, http } from 'viem';
import { base } from 'viem/chains';

const API = 'https://api.gentechlabs.net';
const WALLET = '0x...'; // your wallet

// 1. Call endpoint → get 402 + payment request
const res = await fetch(`${API}/api/v1/agentscan`, {
  headers: { Accept: 'application/json' }
});

if (res.status === 402) {
  const payment = await res.json();

  // 2. Sign the payment request with your wallet
  const signature = await signPayment(payment, WALLET);

  // 3. Retry with the proof
  const data = await fetch(`${API}/api/v1/agentscan`, {
    headers: {
      'Payment-Signature': signature,
      'Payment-Response': 'base64-encoded-response'
    }
  }).then(r => r.json());

  console.log(data);
}
